1188: word16 TLSX_ConnectionID_Write(byte* ext, byte* output)
1189: {
1190:     CIDInfo* info;
1191: 
1192:     info = DtlsCidGetInfoFromExt(ext);
1193:     if (info == NULL)
1194:         return 0;
1195: 
1196:     /* empty CID */
1197:     if (info->rx == NULL) {
1198:         *output = 0;
1199:         return OPAQUE8_LEN;
1200:     }
1201: 
1202:     *output = info->rx->length;
1203:     XMEMCPY(output + OPAQUE8_LEN, info->rx->id, info->rx->length);
1204:     return OPAQUE8_LEN + info->rx->length;
1205: }
